553	
554	    let officia = PathBuf::from(OFFICIA_DIR);
555	    if let Err(e) = std::fs::create_dir_all(&officia) {
556	        return Ok(CallToolResult::error(vec![Content::text(
557	            format!("{}: error creating officia dir: {}", cn, e),
558	        )]));
559	    }
560	
561	    // Exsanguinate stale officia before creating new one
562	    let (reaped, active) = zjjrm_exsanguinate(&officia);
563	
564	    // Generate officium ID and atomically claim the exchange directory.
565	    // create_dir (not create_dir_all) fails with AlreadyExists if another
566	    // session raced to the same ID — retry with next autonumber.
567	    let today = chrono::Local::now().format("%y%m%d").to_string();
568	    let (id, exchange) = loop {
569	        let candidate = zjjrm_generate_officium_id(&officia, &today);
570	        let path = officia.join(&candidate);
571	        match std::fs::create_dir(&path) {
572	            Ok(()) => break (candidate, path),
573	            Err(e) if e.kind() == std::io::ErrorKind::AlreadyExists => continue,
574	            Err(e) => {
575	                return Ok(CallToolResult::error(vec![Content::text(
576	                    format!("{}: error creating exchange dir: {}", cn, e),
