606	        crate::jjrn_notch::JJRN_COMMIT_PREFIX,
607	        &brand,
608	        "",
609	        &action,
610	        &subject,
611	        probe_data.as_deref(),
612	    );
613	
614	    let commit_args = vvc::vvcc_CommitArgs {
615	        prefix: None,
616	        message: Some(message),
617	        allow_empty: true,
618	        no_stage: true,
619	        size_limit: vvc::VVCG_SIZE_LIMIT,
620	        warn_limit: vvc::VVCG_WARN_LIMIT,
621	    };
622	
